<div class="srv-docs-three-cols" style="grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));">
    <!-- EPFO Documents -->
    <div class="srv-docs-col">
        <h3>
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
            EPFO Claims & Member Services
        </h3>
        <div class="srv-docs-num-list">
            <div class="srv-docs-num-item"><div class="srv-docs-number">1</div><div class="srv-docs-text">UAN Details <span>(Number and Password, if activated)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">2</div><div class="srv-docs-text">Aadhaar Card <span>(Must be linked with an active Mobile Number)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">3</div><div class="srv-docs-text">PAN Card</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">4</div><div class="srv-docs-text">Bank Account Details <span>(Passbook or Cancelled Cheque)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">5</div><div class="srv-docs-text">Nominee Details <span>(Aadhaar, Photo & Bank details for e-Nomination)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">6</div><div class="srv-docs-text">Date of Joining & Date of Exit <span>(if applicable)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">7</div><div class="srv-docs-text">Previous Company Details <span>(for PF Transfer)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">8</div><div class="srv-docs-text">Death Certificate & Legal Heir Certificate <span>(for Death Claims)</span></div></div>
        </div>
    </div>
    
    <!-- ESIC Documents -->
    <div class="srv-docs-col">
        <h3>
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
            ESIC Employee Services
        </h3>
        <div class="srv-docs-num-list">
            <div class="srv-docs-num-item"><div class="srv-docs-number">1</div><div class="srv-docs-text">IP Number <span>(Insurance Number)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">2</div><div class="srv-docs-text">Aadhaar Card of Employee</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">3</div><div class="srv-docs-text">Aadhaar Cards of Family Members <span>(for adding dependants)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">4</div><div class="srv-docs-text">Family Photographs</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">5</div><div class="srv-docs-text">Bank Account Details</div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">6</div><div class="srv-docs-text">Medical Certificates <span>(for Sickness or Maternity Benefits)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">7</div><div class="srv-docs-text">Accident Report from Employer <span>(for TDB/PDB)</span></div></div>
            <div class="srv-docs-num-item"><div class="srv-docs-number">8</div><div class="srv-docs-text">Employer Details / TIC Form</div></div>
        </div>
    </div>
</div>
